"use client";

import Link from "next/link";
import { useEffect } from "react";
import { ArrowUpRight } from "lucide-react";

interface MobileMenuProps {
  isOpen: boolean;
  onClose: () => void;
  links: { href: string; label: string }[];
  pathname: string;
}

export default function MobileMenu({
  isOpen,
  onClose,
  links,
  pathname,
}: MobileMenuProps) {
  /* Lock body scroll when open */
  useEffect(() => {
    document.body.style.overflow = isOpen ? "hidden" : "";
    return () => {
      document.body.style.overflow = "";
    };
  }, [isOpen]);

  return (
    <div
      className={`fixed inset-0 z-50 overflow-y-auto bg-gradient-to-b from-[var(--color-custom-light-pink)] to-[var(--color-custom-nude-purple)] transition-all duration-500 lg:hidden ${
        isOpen
          ? "pointer-events-auto opacity-100"
          : "pointer-events-none opacity-0"
      }`}
    >
      {/* Spacer for navbar height */}
      <div className="h-[73px]" />

      {/* Nav links — centered, uppercase, sans-serif */}
      <nav className="flex flex-col items-center gap-10 px-[var(--container-padding-mobile)] pt-12 pb-8">
        {links.map(({ href, label }, i) => (
          <Link
            key={href}
            href={href}
            onClick={onClose}
            className={`text-[var(--font-size-xl)] font-medium uppercase tracking-[0.08em] transition-all duration-500 ${
              isOpen
                ? "translate-y-0 opacity-100"
                : "translate-y-6 opacity-0"
            }`}
            style={{ transitionDelay: `${(i + 1) * 80}ms` }}
          >
            {label}
          </Link>
        ))}

        {/* EMAIL ↗ */}
        <Link
          href="mailto:hello@vsdesign.com"
          onClick={onClose}
          className={`flex items-center gap-2 text-[var(--font-size-xl)] font-medium uppercase tracking-[0.08em] transition-all duration-500 ${
            isOpen
              ? "translate-y-0 opacity-100"
              : "translate-y-6 opacity-0"
          }`}
          style={{ transitionDelay: "320ms" }}
        >
          Email
          <ArrowUpRight size={18} strokeWidth={2} />
        </Link>
      </nav>

      {/* MY WORKS CTA button */}
      <div
        className={`flex justify-center px-[var(--container-padding-mobile)] pt-4 pb-10 transition-all duration-500 ${
          isOpen ? "translate-y-0 opacity-100" : "translate-y-6 opacity-0"
        }`}
        style={{ transitionDelay: "400ms" }}
      >
        <Link
          href="/works"
          onClick={onClose}
          className="inline-flex items-center gap-3 rounded-full bg-[var(--color-fg)] px-10 py-4 text-[var(--font-size-base)] font-medium uppercase tracking-[0.08em] text-[var(--color-bg)] transition-opacity hover:opacity-80"
        >
          My Works
          <ArrowUpRight size={16} strokeWidth={2} />
        </Link>
      </div>
    </div>
  );
}
